mapper.update:
UPDATE pens SET pen_name=#{penName}, capacity=#{capacity},
    responsible_person=#{responsiblePerson}, status=#{status}
WHERE id = #{id}

mapper.select:
SELECT * FROM pens
(pen_code LIKE CONCAT('%', #{search}, '%') OR pen_name LIKE CONCAT('%', #{search}, '%') OR responsible_person LIKE CONCAT('%', #{search}, '%'))
ORDER BY id LIMIT #{size} OFFSET #{offset}
